// Reddit /hot.json -> normalized candidate list.
// Tolerates a failed/blocked Reddit call (returns an empty list instead of crashing).
const res = ($input.first() && $input.first().json) || {};
const children = (res.data && res.data.children) || [];
const candidates = children
  .map(c => c.data)
  .filter(Boolean)
  .map(d => ({
    title: (d.title || '').trim(),
    summary: (d.selftext || '').slice(0, 300),
    url: 'https://www.reddit.com' + (d.permalink || ''),
    source: 'reddit',
    engagement: (d.ups || 0) + (d.num_comments || 0)
  }));
return [{ json: { candidates } }];

// YouTube search -> normalized candidate list (used for both YouTube nodes).
const res = ($input.first() && $input.first().json) || {};
const items = (res.items) || [];
const candidates = items
  .filter(it => it.id && it.id.videoId)
  .map(it => ({
    title: (it.snippet.title || '').trim(),
    summary: (it.snippet.description || '').slice(0, 300),
    url: 'https://www.youtube.com/watch?v=' + it.id.videoId,
    source: 'youtube',
    engagement: 0
  }));
return [{ json: { candidates } }];

