// RSS feed items -> normalized candidate list
const items = $input.all();
const candidates = items
  .map(i => i.json)
  .filter(Boolean)
  .map(a => ({
    title: (a.title || '').trim(),
    summary: (a.contentSnippet || a.content || '').slice(0, 300),
    url: a.link || '',
    source: 'news',
    engagement: 0
  }));
return [{ json: { candidates } }];

// AI-how-to-fit scoring. Keeps only topics that teach the viewer one
// concrete, usable thing about an AI tool (how to use it, or the best
// tools for a task) and that collapse into a tight 30-45s YouTube Short.
// Drops off-niche noise (stocks, crypto, politics).
//
// TOP_N controls how many Short drafts get created per run. Change freely.
const TOP_N = 5;

const all = [];
for (const item of $input.all()) {
  for (const c of (item.json.candidates || [])) all.push(c);
}

// Mentions an AI tool / product
const TOOL = /(\bai\b|chatgpt|\bgpt\b|claude|gemini|grok|midjourney|sora|perplexity|notion ?ai|zapier|n8n|copilot|\bllm\b|ai agent|prompt|automation|deepseek)/i;
// Frames it as something teachable
const HOWTO = /(how to|tutorial|guide|step|use\b|using|set ?up|build|create|automate|workflow|hack|trick|\btip(s)?\b|best |top \d)/i;
// Has a concrete proof number ("7 AI tools", "in 2 minutes", "10x")
const NUM = /(\d+\s?(ai\s?)?tools?|\d+\s?%|in\s?\d+\s?(min|minute|sec|second|hour|day)|\btop\s?\d+\b|\d+x\b)/i;
// Off-niche -> hard penalty
const OFF = /(stock market|crypto|bitcoin|invest|trading|election|politic|nsfw|onlyfans)/i;

function score(c) {
  const t = (c.title || '').trim();
  const blob = (t + ' ' + (c.summary || '')).toLowerCase();
  const words = t.split(/\s+/).filter(Boolean).length;
  let s = 0;
  if (words >= 3 && words <= 16) s += 2;   // collapses into a hook line
  if (TOOL.test(blob)) s += 3;             // actually about an AI tool
  if (HOWTO.test(blob)) s += 3;            // teachable / actionable angle
  if (NUM.test(blob)) s += 2;              // has a concrete proof number
  if (words <= 12) s += 1;                 // short enough for on-screen text
  if (c.engagement > 1000) s += 1;         // already proven to travel
  if (OFF.test(blob)) s -= 5;              // off-niche -> drop
  return s;
}

const seen = new Set();
const scored = all
  .filter(c => c && c.title && c.title.length > 12)
  .map(c => ({ ...c, reel_fit: score(c) }))
  .filter(c => {
    const key = c.title.toLowerCase().slice(0, 50);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  })
  .filter(c => c.reel_fit >= 7)
  .sort((a, b) => b.reel_fit - a.reel_fit)
  .slice(0, TOP_N);

if (scored.length === 0) {
  return [{ json: { skip: true, title: 'NO_AI_TOPICS' } }];
}
return scored.map(c => ({ json: c }));

// Parse the OpenAI JSON and map it onto the Reels tab schema.
let raw;
try {
  let content = $input.item.json.message?.content || $input.item.json.choices?.[0]?.message?.content || '{}';
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  raw = JSON.parse(content);
} catch (e) {
  throw new Error('Failed to parse OpenAI JSON: ' + e.message);
}

const src = $('Code - Score AI-Fit & Pick Top').item.json;
const vo = Array.isArray(raw.voiceover_lines) ? JSON.stringify(raw.voiceover_lines) : '[]';

return {
  Topic: raw.topic || src.title,
  'Key Points': Array.isArray(raw.key_points) ? raw.key_points.join(' | ') : (raw.key_points || ''),
  'Brand Tone': 'Gen Z AI-native energy. Practical, fast, no hype. Teaches young people how to actually use AI tools to work faster.',
  'Enriched Context': (raw.enriched_context || src.summary || '').slice(0, 500),
  'YouTube URL': src.source === 'youtube' ? src.url : '',
  Status: 'Draft',
  'Post Type': 'reel',
  'Headline Line 1 (White)': (raw.headline_line_1 || '').toUpperCase(),
  'Headline Line 2 (Neon Green)': (raw.headline_line_2 || '').toUpperCase(),
  'Headline Line 3 (White)': (raw.headline_line_3 || '').toUpperCase(),
  'Subheadline (Gray)': (raw.subheadline || ''),
  'Key Stat': raw.proof_number || '',
  'Reel Script': raw.reel_script || '',
  'Reel Template': raw.template === 'montage_hook' ? 'montage_hook' : 'five_beat',
  'Voiceover Lines (JSON)': vo,
  'Post Caption': raw.post_caption || '',
  'Reel Fit': src.reel_fit != null ? src.reel_fit : ''
};

// Runs once for ALL appended rows -> builds a single summary email.
// The next step in the lifecycle is the USER: open the Reels tab,
// review/edit the Post Caption, then flip Status -> Ready. Workflow B
// (publisher/workflows/n8n/tweet_card_reel_workflow.json) picks it up
// automatically on the next poll cycle.
const rows = $input.all().map(i => i.json).filter(Boolean);
const count = rows.length;
const sheetUrl = 'https://docs.google.com/spreadsheets/d/13AEU80ULx2Lxnq9SWDeSSFN7unfhr-x_mPyi37oz7O4/edit';

const list = rows
  .map((r, i) => `${i + 1}. ${r.Topic || '(untitled)'}  [${r['Reel Template'] || 'five_beat'}]`)
  .join('\n');

const subject = `${count} new AI Short draft${count === 1 ? '' : 's'} ready for review`;
const body = `Workflow A just added ${count} draft${count === 1 ? '' : 's'} to the Reels tab.\n\n${list}\n\nOpen the Sheet, edit the Post Caption if needed, then flip Status -> Ready:\n${sheetUrl}\n\nWorkflow B will pick it up automatically and trigger the GitHub render job. You'll get the finished mp4 in Drive within ~5 minutes.`;

return [{ json: { subject, body, count } }];
